object UrlValidator {

  // Allowlist of allowed schemes
  private val AllowedSchemes: Set[String] = Set("http", "https")

  // Allowlist of allowed partner API domains
  // In production, load this from configuration
  private val AllowedDomains: Set[String] = Set(
    "api.partner1.com",
    "api.partner2.com",
    "hooks.partner3.io",
    "webhook.example.com"
  )

  // Blocked port ranges - only allow standard HTTP(S) ports
  private val AllowedPorts: Set[Int] = Set(80, 443, 8080, 8443)

  def validate(rawUrl: String): Either[String, URI] = {
    for {
      uri        <- parseUri(rawUrl)
      _          <- validateScheme(uri)
      host       <- extractHost(uri)
      _          <- validateDomainAllowlist(host)
      _          <- validatePort(uri)
      resolvedIps <- resolveHost(host)
      _          <- validateNotInternalIp(resolvedIps, host)
    } yield uri
  }

  private def parseUri(rawUrl: String): Either[String, URI] = {
    Try(new URI(rawUrl)) match {
      case Success(uri) if uri.getHost != null => Right(uri)
      case Success(_) => Left("URL must have a valid host component")
      case Failure(_) => Left("Invalid URL format")
    }
  }

  private def validateScheme(uri: URI): Either[String, Unit] = {
    val scheme = Option(uri.getScheme).map(_.toLowerCase).getOrElse("")
    if (AllowedSchemes.contains(scheme)) Right(())
    else Left(s"Scheme '$scheme' is not allowed. Only ${AllowedSchemes.mkString(", ")} are permitted.")
  }

  private def extractHost(uri: URI): Either[String, String] = {
    Option(uri.getHost).map(_.toLowerCase) match {
      case Some(host) if host.nonEmpty => Right(host)
      case _ => Left("URL must contain a valid host")
    }
  }

  private def validateDomainAllowlist(host: String): Either[String, Unit] = {
    if (AllowedDomains.contains(host)) Right(())
    else Left(s"Host '$host' is not in the allowed partner domains list")
  }

  private def validatePort(uri: URI): Either[String, Unit] = {
    val port = uri.getPort match {
      case -1 =>
        Option(uri.getScheme).map(_.toLowerCase) match {
          case Some("https") => 443
          case Some("http")  => 80
          case _             => -1
        }
      case p => p
    }
    if (AllowedPorts.contains(port)) Right(())
    else Left(s"Port $port is not allowed. Only ports ${AllowedPorts.mkString(", ")} are permitted.")
  }

  private def resolveHost(host: String): Either[String, Array[InetAddress]] = {
    try {
      val addresses = InetAddress.getAllByName(host)
      if (addresses.isEmpty) Left(s"Could not resolve host: $host")
      else Right(addresses)
    } catch {
      case _: UnknownHostException => Left(s"Could not resolve host: $host")
    }
  }

  private def validateNotInternalIp(addresses: Array[InetAddress], host: String): Either[String, Unit] = {
    val hasInternalAddress = addresses.exists(isInternalAddress)
    if (hasInternalAddress) Left(s"Host '$host' resolves to an internal/private IP address, which is not allowed")
    else Right(())
  }

  private def isInternalAddress(addr: InetAddress): Boolean = {
    addr.isLoopbackAddress ||
      addr.isLinkLocalAddress ||
      addr.isSiteLocalAddress ||
      addr.isAnyLocalAddress ||
      addr.isMulticastAddress ||
      isIPv4Mapped(addr) ||
      isMetadataAddress(addr)
  }

  private def isIPv4Mapped(addr: InetAddress): Boolean = {
    val bytes = addr.getAddress
    // Check for IPv4-mapped IPv6 addresses that wrap private IPv4
    if (bytes.length == 16) {
      // Extract the IPv4 part from ::ffff:x.x.x.x
      val allZeroPrefix = (0 until 10).forall(i => bytes(i) == 0)
      val ffffMarker = bytes(10) == 0xff.toByte && bytes(11) == 0xff.toByte
      if (allZeroPrefix && ffffMarker) {
        val ipv4Bytes = bytes.slice(12, 16)
        try {
          val ipv4Addr = InetAddress.getByAddress(ipv4Bytes)
          return isInternalAddressIPv4(ipv4Addr)
        } catch {
          case _: Exception => false
        }
      }
    }
    false
  }

  private def isInternalAddressIPv4(addr: InetAddress): Boolean = {
    addr.isLoopbackAddress ||
      addr.isLinkLocalAddress ||
      addr.isSiteLocalAddress ||
      addr.isAnyLocalAddress ||
      isMetadataAddress(addr)
  }

  // Block cloud metadata endpoints (169.254.169.254, etc.)
  private def isMetadataAddress(addr: InetAddress): Boolean = {
    val ip = addr.getHostAddress
    ip == "169.254.169.254" || // AWS/GCP/Azure metadata
      ip == "100.100.100.200" || // Alibaba Cloud metadata
      ip.startsWith("fd00:")     // IPv6 ULA
  }
}

object WebhookProxyService extends App {

  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: Materializer = Materializer(system)
  implicit val executionContext: ExecutionContext = system.dispatcher

  import JsonProtocol._

  // Maximum response body size to prevent memory exhaustion
  private val MaxResponseBodySize = 1024 * 1024 // 1 MB

  // Request timeout is handled by Akka HTTP client settings
  // Configure in application.conf: akka.http.client.connecting-timeout, akka.http.client.idle-timeout

  private val MaxRedirects = 0 // Do not follow redirects to prevent SSRF via redirect

  private def fetchUrl(validatedUri: URI): Future[WebhookResponse] = {
    val request = HttpRequest(
      method = HttpMethods.GET,
      uri = validatedUri.toString
    )

    // Use Http().singleRequest which does NOT follow redirects by default
    Http().singleRequest(request).flatMap { response =>
      val statusCode = response.status.intValue()

      // If we get a redirect, do NOT follow it - return error instead
      if (statusCode >= 300 && statusCode < 400) {
        response.discardEntityBytes()
        Future.successful(WebhookResponse(
          status = statusCode,
          body = s"Redirect detected (HTTP $statusCode). Redirects are not followed for security reasons."
        ))
      } else {
        // Limit response body size
        response.entity.withSizeLimit(MaxResponseBodySize)
        Unmarshal(response.entity).to[String].map { body =>
          WebhookResponse(status = statusCode, body = body)
        }.recover {
          case ex: akka.http.scaladsl.model.EntityStreamSizeException =>
            WebhookResponse(status = statusCode, body = "Response body exceeded maximum allowed size")
          case ex =>
            WebhookResponse(status = statusCode, body = s"Error reading response: ${ex.getMessage}")
        }
      }
    }
  }

  val route =
    path("webhook" / "proxy") {
      post {
        entity(as[WebhookRequest]) { request =>
          // Validate the URL before making any outbound request
          UrlValidator.validate(request.url) match {
            case Left(errorMsg) =>
              complete(StatusCodes.BadRequest -> ErrorResponse(s"URL validation failed: $errorMsg"))

            case Right(validatedUri) =>
              // Perform DNS re-validation right before the request to mitigate TOCTOU
              val revalidation = Future {
                val host = validatedUri.getHost
                val addresses = InetAddress.getAllByName(host)
                val hasInternal = addresses.exists { addr =>
                  addr.isLoopbackAddress ||
                    addr.isLinkLocalAddress ||
                    addr.isSiteLocalAddress ||
                    addr.isAnyLocalAddress ||
                    addr.isMulticastAddress
                }
                if (hasInternal) {
                  throw new SecurityException(s"Host '$host' resolves to internal address on re-check")
                }
              }

              val result = revalidation.flatMap(_ => fetchUrl(validatedUri))

              onComplete(result) {
                case Success(webhookResponse) =>
                  complete(StatusCodes.OK -> webhookResponse)
                case Failure(ex: SecurityException) =>
                  complete(StatusCodes.BadRequest -> ErrorResponse(s"Security check failed: ${ex.getMessage}"))
                case Failure(ex) =>
                  complete(StatusCodes.BadGateway -> ErrorResponse(s"Failed to fetch URL: ${ex.getMessage}"))
              }
          }
        }
      }
    } ~
      path("health") {
        get {
          complete(StatusCodes.OK -> JsObject("status" -> JsString("healthy")))
        }
      }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      val address = binding.localAddress
      println(s"Webhook proxy service online at http://${address.getHostString}:${address.getPort}/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }
}